// Sadə async/await nümunəsi
function fetchData() {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ id: 1, name: 'Ali' });
    }, 1000);
  });
}

async function getData() {
  const data = await fetchData();
  console.log('Məlumat alındı: ', data.name);
}

getData(); // 1 saniyə sonra: Məlumat alındı: Ali

// Xəta idarəetmə nümunəsi
function fetchDataWithError() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject('Məlumat alınmadı');
    }, 1000);
  });
}

async function getDataSafe() {
  try {
    const data = await fetchDataWithError();
    console.log(data);
  } catch (error) {
    console.log('Xəta: ', error);
  }
}

getDataSafe(); // 1 saniyə sonra: Xəta: Məlumat alınmadı

// Ardıcıl async/await nümunəsi
function fetchUser() {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ id: 2, name: 'Veli' });
    }, 1000);
  });
}

function fetchDetails(user) {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ userId: user.id, detail: 'Əlavə məlumat' });
    }, 1000);
  });
}

async function getUserDetails() {
  const user = await fetchUser();
  const details = await fetchDetails(user);
  console.log('İstifadəçi: ', user.name, 'Detallar: ', details.detail);
}

getUserDetails(); // 2 saniyə sonra: İstifadəçi: Veli Detallar: Əlavə məlumat

// Səhvə yol açan nümunə
function fetchData() {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve(null);
    }, 1000);
  });
}

async function getData() {
  const data = await fetchData();
  console.log(data.name); // TypeError: Cannot read property 'name' of null
}

getData();

// Düzgün yol
async function getDataSafe() {
  try {
    const data = await fetchData();
    if (!data) throw new Error('Məlumat yoxdur');
    console.log(data.name);
  } catch (error) {
    console.log('Xəta: ', error.message);
  }
}

getDataSafe(); // Xəta: Məlumat yoxdur

// Promise.all ilə async/await nümunəsi
function fetchData1() {
  return new Promise((resolve) => {
    setTimeout(() => resolve('Birinci məlumat'), 1000);
  });
}

function fetchData2() {
  return new Promise((resolve) => {
    setTimeout(() => resolve('İkinci məlumat'), 2000);
  });
}

async function getAllData() {
  try {
    const results = await Promise.all([fetchData1(), fetchData2()]);
    console.log('Bütün nəticələr: ', results);
  } catch (error) {
    console.log('Xəta: ', error);
  }
}

getAllData(); // 2 saniyə sonra: Bütün nəticələr: ['Birinci məlumat', 'İkinci məlumat']

