// Sequential async/await example
function fetchUser() {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ id: 2, name: 'Veli' });
    }, 1000);
  });
}

function fetchDetails(user) {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({ userId: user.id, detail: 'Additional info' });
    }, 1000);
  });
}

async function getUserDetails() {
